 text-green-400"}, {"text": "photographer", "style": "border-purple-500/30 text-purple-400"}, {"text": "minimalism", "style": "border-gray-500/30 text-gray-400"}], "techStack": ["Java", "Spring Boot", "MyBatis", "MySQL", "Redis", "Vue 3", "TypeScript", "Tailwind CSS", "Docker", "Git"]}}}}' WHERE id = 2;

